import{_ as e,o as a,c as s,ag as n}from"./chunks/framework.B80GRNWb.js";const u=JSON.parse('{"title":"核心概念","description":"","frontmatter":{},"headers":[],"relativePath":"guide/concepts.md","filePath":"guide/concepts.md","lastUpdated":1774526577000}'),o={name:"guide/concepts.md"};function l(d,t,r,i,c,p){return a(),s("div",null,[...t[0]||(t[0]=[n(`<h1 id="核心概念" tabindex="-1">核心概念 <a class="header-anchor" href="#核心概念" aria-label="Permalink to &quot;核心概念&quot;">​</a></h1><p>本节介绍 AeroLoongClaw 的核心架构概念。详细内容请参阅 <a href="/aeroloongclaw/reference/architecture.html">架构详解</a>。</p><h2 id="群组隔离模型" tabindex="-1">群组隔离模型 <a class="header-anchor" href="#群组隔离模型" aria-label="Permalink to &quot;群组隔离模型&quot;">​</a></h2><p>每个群组（Group）在独立隔离的环境中运行：</p><ul><li><strong>文件系统隔离</strong>：每个群组有独立的 <code>/workspace/group</code> 目录</li><li><strong>会话隔离</strong>：群组间的对话上下文和 session 数据不共享</li><li><strong>IPC 隔离</strong>：每个群组有独立的 IPC namespace (<code>/workspace/ipc</code>)</li><li><strong>存储隔离</strong>：群组间不共享 media 存储</li></ul><h2 id="容器生命周期" tabindex="-1">容器生命周期 <a class="header-anchor" href="#容器生命周期" aria-label="Permalink to &quot;容器生命周期&quot;">​</a></h2><p>Agent 在 Docker 容器中隔离执行：</p><ol><li><strong>Spawn</strong>：Host 通过 <code>ContainerRunner</code> 启动容器</li><li><strong>Input</strong>：通过 stdin 传入 <code>ContainerInput</code> JSON（prompt、secrets、model、skills）</li><li><strong>Execute</strong>：OpenCode Runtime 在容器内运行 agent</li><li><strong>Output</strong>：通过 <code>OUTPUT_START/END</code> markers 从 stdout 解析结构化结果</li><li><strong>IPC</strong>：容器通过文件系统（JSON 文件）向 Host 发送消息/任务/技能事件</li><li><strong>Cleanup</strong>：容器在 idle 或超时后退出</li></ol><h2 id="ipc-机制" tabindex="-1">IPC 机制 <a class="header-anchor" href="#ipc-机制" aria-label="Permalink to &quot;IPC 机制&quot;">​</a></h2><p>文件系统-based IPC，原子写入：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>data/ipc/{group}/</span></span>
<span class="line"><span>├── messages/     # 容器 → Host 发送消息</span></span>
<span class="line"><span>├── tasks/        # 定时任务调度</span></span>
<span class="line"><span>├── input/        # 运行控制（_close 等 sentinel）</span></span>
<span class="line"><span>└── skills/       # 技能加载事件</span></span></code></pre></div><h2 id="四层指令系统" tabindex="-1">四层指令系统 <a class="header-anchor" href="#四层指令系统" aria-label="Permalink to &quot;四层指令系统&quot;">​</a></h2><p>每个群组有四层 instruction 文件，优先级从高到低：</p><table tabindex="0"><thead><tr><th>文件</th><th>用途</th><th>合并策略</th></tr></thead><tbody><tr><td><code>SOUL.md</code></td><td>Agent 的核心人格/价值导向</td><td>Override 覆盖</td></tr><tr><td><code>USER.md</code></td><td>用户偏好和使用约束</td><td>Override 覆盖</td></tr><tr><td><code>AGENTS.md</code></td><td>Agent 行为规范</td><td>Override 覆盖</td></tr><tr><td><code>MEMORY.md</code></td><td>积累的上下文记忆</td><td>增量追加</td></tr></tbody></table><h2 id="消息驱动流程" tabindex="-1">消息驱动流程 <a class="header-anchor" href="#消息驱动流程" aria-label="Permalink to &quot;消息驱动流程&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户消息 → Channel → SQLite → Polling Loop → Group Queue</span></span>
<span class="line"><span>  → Container Runner → Docker 容器 → OpenCode Runtime</span></span>
<span class="line"><span>  → IPC 文件 → Host IPC Watcher → Router → Channel → 用户</span></span></code></pre></div><h2 id="skills-系统" tabindex="-1">Skills 系统 <a class="header-anchor" href="#skills-系统" aria-label="Permalink to &quot;Skills 系统&quot;">​</a></h2><p>77+ 运行时技能，分为 4 类：</p><ul><li><strong>31 built-in skills</strong>：内置于 <code>skills/</code> 目录</li><li><strong>Plugin skills</strong>：来自 knowledge-work-plugins 的可插拔技能</li><li><strong>Custom skills</strong>：用户通过 <code>npm run skill:install</code> 安装</li></ul><p>Skills 以 SKILL.md 格式定义，容器内通过 <code>/workspace/skills/</code> 只读挂载访问。</p><h2 id="运行时控制" tabindex="-1">运行时控制 <a class="header-anchor" href="#运行时控制" aria-label="Permalink to &quot;运行时控制&quot;">​</a></h2><p>支持数字回复控制正在运行的 Agent：</p><table tabindex="0"><thead><tr><th>回复</th><th>含义</th></tr></thead><tbody><tr><td><code>4</code></td><td>查看当前进展</td></tr><tr><td><code>5</code></td><td>停下来</td></tr><tr><td><code>6</code></td><td>从头再来</td></tr></tbody></table><p>详细说明请参阅 <a href="/aeroloongclaw/reference/architecture.html">架构详解</a>。</p>`,24)])])}const g=e(o,[["render",l]]);export{u as __pageData,g as default};
